// ===== GETDEADDICTED ACADEMY — EXPANDED COURSE CONTENT =====
// This file enriches existing courses with detailed module content, narrations, and exercises

function expandCourses(courses) {
  const expansions = getExpansions();
  return courses.map(course => {
    const exp = expansions[course.id];
    if (!exp) return course;
    return {
      ...course,
      description: exp.description || course.description,
      introduction: exp.introduction,
      detailedOutcomes: exp.detailedOutcomes || course.outcomes,
      modules: course.modules.map((mod, i) => {
        const modTitle = typeof mod === 'string' ? mod : mod.title;
        const modExp = exp.modules && exp.modules[i];
        if (!modExp) return { title: modTitle, overview: "", keyPoints: [], narration: "", exercise: "", duration: "15 min" };
        return {
          title: modTitle,
          overview: modExp.overview,
          keyPoints: modExp.keyPoints,
          narration: modExp.narration,
          exercise: modExp.exercise,
          duration: modExp.duration || "15 min"
        };
      })
    };
  });
}

